import numpy as np
from collections import deque

def solve(grid):
    grid = np.array(grid)
    H, W = grid.shape
    bg = int(np.bincount(grid.flatten()).argmax())

    non_bg = list(zip(*np.where(grid != bg)))

    visited = set()
    components = []
    for r, c in non_bg:
        if (r, c) in visited:
            continue
        comp = []
        queue = deque([(r, c)])
        visited.add((r, c))
        while queue:
            cr, cc = queue.popleft()
            comp.append((cr, cc))
            for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                nr, nc = cr+dr, cc+dc
                if 0 <= nr < H and 0 <= nc < W and (nr, nc) not in visited and grid[nr, nc] != bg:
                    visited.add((nr, nc))
                    queue.append((nr, nc))
        components.append(comp)

    small_pattern_cells = []
    large_block_components = []
    for comp in components:
        if len(comp) == 1:
            small_pattern_cells.append(comp[0])
        else:
            large_block_components.append(comp)

    sp_rows = sorted(set(r for r, c in small_pattern_cells))
    sp_cols = sorted(set(c for r, c in small_pattern_cells))

    sp_row_idx = {r: i for i, r in enumerate(sp_rows)}
    sp_col_idx = {c: i for i, c in enumerate(sp_cols)}

    n_sp_rows = len(sp_rows)
    n_sp_cols = len(sp_cols)

    sp_grid = [[bg] * n_sp_cols for _ in range(n_sp_rows)]
    for r, c in small_pattern_cells:
        sp_grid[sp_row_idx[r]][sp_col_idx[c]] = int(grid[r, c])

    large_blocks = []
    for comp in large_block_components:
        rows = [r for r, c in comp]
        cols = [c for r, c in comp]
        r_min, r_max = min(rows), max(rows)
        c_min, c_max = min(cols), max(cols)
        color = int(grid[r_min, c_min])
        large_blocks.append({
            'r': r_min, 'c': c_min,
            'h': r_max - r_min + 1, 'w': c_max - c_min + 1,
            'color': color
        })

    large_blocks.sort(key=lambda b: b['c'])

    block_h = large_blocks[0]['h']
    block_w = large_blocks[0]['w']

    if len(large_blocks) >= 2:
        stride = large_blocks[1]['c'] - large_blocks[0]['c']
    else:
        stride = block_w + 1

    lb_colors = [b['color'] for b in large_blocks]
    n_lb = len(lb_colors)

    best_match = None
    for row_idx in range(n_sp_rows):
        row_colors = sp_grid[row_idx]
        for start_col in range(n_sp_cols - n_lb + 1):
            match = True
            for j in range(n_lb):
                if row_colors[start_col + j] != lb_colors[j]:
                    match = False
                    break
            if match:
                best_match = (row_idx, start_col)
                break
        if best_match:
            break

    match_row, match_start_col = best_match

    base_row = large_blocks[0]['r']
    base_col = large_blocks[0]['c']

    col0_pos = base_col - match_start_col * stride
    row0_pos = base_row - match_row * stride

    output = grid.copy()

    for i in range(n_sp_rows):
        for j in range(n_sp_cols):
            color = sp_grid[i][j]
            if color == bg:
                continue
            r_start = row0_pos + i * stride
            c_start = col0_pos + j * stride
            for dr in range(block_h):
                for dc in range(block_w):
                    r = r_start + dr
                    c = c_start + dc
                    if 0 <= r < H and 0 <= c < W:
                        output[r, c] = color

    return output.tolist()

# Test on training examples
for i, s in enumerate(train_samples):
    result = solve(s['input'])
    expected = s['output']
    match = result == expected
    print(f"Example {i}: {'PASS' if match else 'FAIL'}")
    if not match:
        result_arr = np.array(result)
        expected_arr = np.array(expected)
        diff = np.where(result_arr != expected_arr)
        print(f"  Differences at {len(diff[0])} positions")
        for r, c in zip(diff[0][:10], diff[1][:10]):
            print(f"  ({int(r)},{int(c)}): got {int(result_arr[r,c])}, expected {int(expected_arr[r,c])}")

